#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding mobility-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    occupation:string! \
    ethnicity:string! \
    contact_phone:string! \
    contact_email:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    gp_name:string! \
    gp_practice:string! \
    living_environment:string! \
    stairs_at_home:string! \
    --htmx

cargo loco generate scaffold assessment_referral_information \
    assessment:references \
    referring_clinician:string! \
    referring_organisation:string! \
    referral_date:date \
    referral_reason:text! \
    previous_mobility_assessment:string! \
    previous_assessment_date:date \
    previous_tinetti_score:int \
    --htmx

cargo loco generate scaffold assessment_fall_history \
    assessment:references \
    falls_in_past_12_months:string! \
    fall_count:int \
    most_recent_fall_date:date \
    fall_circumstances:text! \
    fall_injuries:string! \
    fall_injury_details:text! \
    fracture_from_fall:string! \
    fracture_details:text! \
    hospitalisation_from_fall:string! \
    fear_of_falling:string! \
    activity_restriction_due_to_fear:string! \
    near_falls:string! \
    near_fall_frequency:string! \
    fall_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_balance_assessment \
    assessment:references \
    sitting_balance:int \
    arising_from_chair:int \
    attempts_to_arise:int \
    immediate_standing_balance:int \
    standing_balance:int \
    nudge_test:int \
    eyes_closed:int \
    turning_360:int \
    sitting_down:int \
    balance_total_score:int \
    balance_notes:text! \
    --htmx

cargo loco generate scaffold assessment_gait_assessment \
    assessment:references \
    initiation_of_gait:int \
    step_length_right:int \
    step_length_left:int \
    step_height_right:int \
    step_height_left:int \
    step_symmetry:int \
    step_continuity:int \
    path_deviation:int \
    trunk_sway:int \
    walking_stance:int \
    gait_total_score:int \
    gait_notes:text! \
    --htmx

cargo loco generate scaffold assessment_timed_up_and_go \
    assessment:references \
    tug_time_seconds:double \
    tug_risk_category:string! \
    assistive_device_used:string! \
    assistive_device_type:string! \
    unsteadiness_observed:string! \
    required_physical_assistance:string! \
    trial_count:int \
    tug_notes:text! \
    --htmx

cargo loco generate scaffold assessment_range_of_motion \
    assessment:references \
    hip_flexion_left:int \
    hip_flexion_right:int \
    hip_extension_left:int \
    hip_extension_right:int \
    knee_flexion_left:int \
    knee_flexion_right:int \
    knee_extension_left:int \
    knee_extension_right:int \
    ankle_dorsiflexion_left:int \
    ankle_dorsiflexion_right:int \
    ankle_plantarflexion_left:int \
    ankle_plantarflexion_right:int \
    joint_pain:string! \
    joint_pain_details:text! \
    joint_stiffness:string! \
    range_of_motion_notes:text! \
    --htmx

cargo loco generate scaffold assessment_assistive_devices \
    assessment:references \
    uses_assistive_device:string! \
    walking_stick:string! \
    walking_frame:string! \
    rollator:string! \
    wheelchair:string! \
    wheelchair_type:string! \
    orthotics:string! \
    orthotics_details:text! \
    other_device:text! \
    device_condition:string! \
    device_appropriate:string! \
    device_used_correctly:string! \
    home_adaptations:text! \
    assistive_device_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    polypharmacy:string! \
    total_medication_count:int \
    fall_risk_medications:string! \
    sedatives:string! \
    antihypertensives:string! \
    diuretics:string! \
    psychotropics:string! \
    opioids:string! \
    anticonvulsants:string! \
    postural_hypotension:string! \
    recent_medication_changes:string! \
    medication_change_details:text! \
    medication_notes:text! \
    --htmx

cargo loco generate scaffold assessment_functional_independence \
    assessment:references \
    transfers:string! \
    indoor_mobility:string! \
    outdoor_mobility:string! \
    stair_negotiation:string! \
    bathing:string! \
    dressing:string! \
    toileting:string! \
    meal_preparation:string! \
    shopping:string! \
    community_access:string! \
    carer_support:string! \
    carer_details:text! \
    functional_goals:text! \
    functional_independence_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    balance_score:int! \
    gait_score:int! \
    total_tinetti_score:int! \
    fall_risk_category:string! \
    tug_time_seconds:double \
    tug_risk_category:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
